async function getStreetlightTimes(dateStr, lat = 47.6062, lon = -122.3321) {
  const url = `https://api.sunrise-sunset.org/json?lat=${lat}&lng=${lon}&date=${dateStr}&formatted=0`;
  const resp = await fetch(url);
  const data = (await resp.json()).results;

  return {
    lightsOn: new Date(data.civil_twilight_end),   // best estimate
    lightsOff: new Date(data.civil_twilight_begin), // best estimate
    sunset: new Date(data.sunset),
    sunrise: new Date(data.sunrise),
  };
}

function areStreetlightsOn(now, sunTimes) {
  return now >= sunTimes.lightsOn || now <= sunTimes.lightsOff;
}
